      const body = { done: fd.get('done'), today: fd.get('today'), blockers: fd.get('blockers'), agent: (currentUser && currentUser.email) || 'Admin' };
      try {
        await fetchJson('/fleet/api/standup', { method: 'POST', body: JSON.stringify(body) });
        e.target.reset();
        loadDailyStandups();
      } catch (err) { alert('Failed to save.'); }
    };
  }

  const taskForm = document.getElementById('task-form');
  if (taskForm) {
    taskForm.onsubmit = async (e) => {
      e.preventDefault();
      const fd = new FormData(e.target);
      const skillsRaw = fd.get('required_skills') || '';
      const skills = skillsRaw.split(',').map(s => s.trim()).filter(Boolean);

      const body = {
        title: fd.get('title'),
        description: fd.get('description'),
        assigned_agent: fd.get('assigned_agent'),
        status: 'todo',
        required_skills: skills
      };

      try {
        // We use the PocketBase API directly if available, or via server proxy
        // Since we are in the dashboard, we use the server proxy
        // But the server doesn't have a POST /tasks endpoint yet?
        // Actually, many of these are handled by the dashboard's own API
        // I'll check if there's a POST /fleet/api/tasks
        await fetchJson('/fleet/api/tasks', { 
          method: 'POST', 
          body: JSON.stringify(body) 
        });
        closeTaskModal();
        e.target.reset();
        loadKanban();
      } catch (err) { alert('Failed to create task.'); }
    };
  }
}

async function loadUsers() {
  const container = document.getElementById('users-list');
  if (!container) return;
  try {
    const data = await fetchJson('/fleet/api/users');
    container.innerHTML = (data.users || []).map(u => `
      <div class="agent-card" style="margin-bottom: 4px;">
        <div class="card-summary">
          <span style="flex: 1; font-size: 13px;">${u}</span>
          <button class="btn-link" onclick="removeUser('${u}')">Remove</button>
        </div>
